using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords =
    [
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "above", "below",
        "between", "out", "off", "over", "under", "again", "further",
        "then", "once", "here", "there", "when", "where", "why", "how",
        "all", "each", "every", "both", "few", "more", "most", "other",
        "some", "such", "no", "nor", "not", "only", "own", "same", "so",
        "than", "too", "very", "can", "will", "just", "should", "now",
        "it", "its", "this", "that", "these", "those", "i", "me", "my",
        "we", "our", "you", "your", "he", "him", "his", "she", "her",
        "they", "them", "their", "what", "which", "who", "whom",
        "do", "does", "did", "has", "have", "had", "be", "been", "being",
        "would", "could", "might", "shall", "may", "about", "up"
    ];

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency
    /// and returning the top-ranked sentences in their original order.
    /// </summary>
    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    public static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundaryRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                var lower = word.ToLowerInvariant();
                if (!StopWords.Contains(lower) && lower.Length > 1)
                {
                    frequencies[lower] = frequencies.GetValueOrDefault(lower) + 1;
                }
            }
        }

        return frequencies;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = TokenizeWords(sentence);
            if (words.Count == 0)
            {
                scores.Add(0);
                continue;
            }

            double score = words
                .Select(w => w.ToLowerInvariant())
                .Where(w => wordFrequencies.ContainsKey(w))
                .Sum(w => wordFrequencies[w]);

            // Normalize by word count to avoid bias toward long sentences
            scores.Add(score / words.Count);
        }

        return scores;
    }

    private static List<string> TokenizeWords(string text)
    {
        return WordTokenRegex()
            .Matches(text)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundaryRegex();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordTokenRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizationController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizationService;

    public SummarizationController(DocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var sentences = DocumentSummarizationService.SplitIntoSentences(request.DocumentText);
        var summary = _summarizationService.Summarize(request.DocumentText, request.MaxSentences);
        var summarySentenceCount = DocumentSummarizationService.SplitIntoSentences(summary).Count;

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = summarySentenceCount
        });
    }
}

