using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizationController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizationService;

    public SummarizationController(DocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var sentences = DocumentSummarizationService.SplitIntoSentences(request.DocumentText);
        var summary = _summarizationService.Summarize(request.DocumentText, request.MaxSentences);
        var summarySentenceCount = DocumentSummarizationService.SplitIntoSentences(summary).Count;

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = summarySentenceCount
        });
    }
}

